#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef long long ll;

int compare(const void *a, const void *b) {
    return (*(ll*)b - *(ll*)a);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K1, K2, K3;
        scanf("%d %d %d %d", &N, &K1, &K2, &K3);
        ll A[N], sums[N * (N + 1) / 2], sum;
        int count = 0;
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            sum = 0;
            for (int j = i; j < N; j++) {
                sum += A[j];
                sums[count++] = sum;
            }
        }
        qsort(sums, count, sizeof(ll), compare);
        printf("%lld %lld %lld\n", sums[K1 - 1], sums[K2 - 1], sums[K3 - 1]);
    }
    return 0;
}

